#include <bits/stdc++.h>
using namespace std;
long long a[1000010],r[1000010];
long long e(long long g)
{
    long long p=0;
    for(long long i=0;i<g;i++)
    {
        cin>>a[i];
    }
    for(long long i=0;i<g;i++)
    {
        cin>>r[i];
    }
    for(long long i=0;i<g;i++)
        {
            if(a[i]<r[i])
            {
                p+=r[i]-a[i];
            }
        }
    return p;
}
int main()
{
    long long n,c,b=0;
    cin>>n>>c;
    b=e(n);
    cout<<b*c;
    return 0;
}
